arguments.content:
$procs = Get-Process Unity -ErrorAction SilentlyContinue
$found = $false
foreach ($p in $procs) {
    $cmd = (Get-CimInstance Win32_Process -Filter "ProcessId=$($p.Id)").CommandLine
    if ($cmd -match 'RunHotUpdatePipeline') {
        Write-Host "Found pipeline process: PID=$($p.Id)"
        $found = $true
    }
}
if (-not $found) { Write-Host "No pipeline process found" }
